#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

#define EXPAND_RATE 2
#define AMB_TEMP 80.0f

inline float compute_point(int r, int c, int row, int col,
                           float temp_c, float temp_n, float temp_s,
                           float temp_w, float temp_e,
                           float power_c,
                           float Cap_1, float Rx_1, float Ry_1, float Rz_1)
{
    float delta;

    if ((r == 0) && (c == 0)) {
        delta = Cap_1 * (power_c +
                         (temp_e - temp_c) * Rx_1 +
                         (temp_s - temp_c) * Ry_1 +
                         (AMB_TEMP - temp_c) * Rz_1);
    } else if ((r == 0) && (c == col - 1)) {
        delta = Cap_1 * (power_c +
                         (temp_w - temp_c) * Rx_1 +
                         (temp_s - temp_c) * Ry_1 +
                         (AMB_TEMP - temp_c) * Rz_1);
    } else if ((r == row - 1) && (c == col - 1)) {
        delta = Cap_1 * (power_c +
                         (temp_w - temp_c) * Rx_1 +
                         (temp_n - temp_c) * Ry_1 +
                         (AMB_TEMP - temp_c) * Rz_1);
    } else if ((r == row - 1) && (c == 0)) {
        delta = Cap_1 * (power_c +
                         (temp_e - temp_c) * Rx_1 +
                         (temp_n - temp_c) * Ry_1 +
                         (AMB_TEMP - temp_c) * Rz_1);
    } else if (r == 0) {
        delta = Cap_1 * (power_c +
                         (temp_e + temp_w - 2.0f * temp_c) * Rx_1 +
                         (temp_s - temp_c) * Ry_1 +
                         (AMB_TEMP - temp_c) * Rz_1);
    } else if (c == col - 1) {
        delta = Cap_1 * (power_c +
                         (temp_s + temp_n - 2.0f * temp_c) * Ry_1 +
                         (temp_w - temp_c) * Rx_1 +
                         (AMB_TEMP - temp_c) * Rz_1);
    } else if (r == row - 1) {
        delta = Cap_1 * (power_c +
                         (temp_e + temp_w - 2.0f * temp_c) * Rx_1 +
                         (temp_n - temp_c) * Ry_1 +
                         (AMB_TEMP - temp_c) * Rz_1);
    } else if (c == 0) {
        delta = Cap_1 * (power_c +
                         (temp_s + temp_n - 2.0f * temp_c) * Ry_1 +
                         (temp_e - temp_c) * Rx_1 +
                         (AMB_TEMP - temp_c) * Rz_1);
    } else {
        delta = Cap_1 * (power_c +
                         (temp_s + temp_n - 2.0f * temp_c) * Ry_1 +
                         (temp_e + temp_w - 2.0f * temp_c) * Rx_1 +
                         (AMB_TEMP - temp_c) * Rz_1);
    }

    return temp_c + delta;
}

__kernel void hotspot(int iteration,
                      __global const float *power,
                      __global const float *temp_src,
                      __global float *temp_dst,
                      int col,
                      int row,
                      int borderCols,
                      int borderRows,
                      float Cap,
                      float Rx,
                      float Ry,
                      float Rz,
                      float step)
{
    const int tx = get_local_id(0);
    const int ty = get_local_id(1);
    const int bx = get_group_id(0);
    const int by = get_group_id(1);

    const int small_block_cols = BLOCK_SIZE - iteration * EXPAND_RATE;
    const int small_block_rows = BLOCK_SIZE - iteration * EXPAND_RATE;

    const int blkX = small_block_cols * bx - borderCols;
    const int blkY = small_block_rows * by - borderRows;

    const int xidx = blkX + tx;
    const int yidx = blkY + ty;

    const int valid = (xidx >= 0 && xidx < col && yidx >= 0 && yidx < row);

    const float Rx_1 = 1.0f / Rx;
    const float Ry_1 = 1.0f / Ry;
    const float Rz_1 = 1.0f / Rz;
    const float Cap_1 = (step * 0.001f) / Cap;

    __local float temp0[BLOCK_SIZE][BLOCK_SIZE];
    __local float temp1[BLOCK_SIZE][BLOCK_SIZE];
    __local float power_local[BLOCK_SIZE][BLOCK_SIZE];

    if (valid) {
        const int index = yidx * col + xidx;
        temp0[ty][tx] = temp_src[index];
        power_local[ty][tx] = power[index];
    } else {
        temp0[ty][tx] = 0.0f;
        power_local[ty][tx] = 0.0f;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    int buf = 0;

    for (int i = 0; i < iteration; i++) {
        const int txmin = i + 1;
        const int txmax = BLOCK_SIZE - i - 2;
        const int tymin = i + 1;
        const int tymax = BLOCK_SIZE - i - 2;

        if (valid &&
            tx >= txmin && tx <= txmax &&
            ty >= tymin && ty <= tymax) {

            float tc, tn, ts, tw, te;

            if (buf == 0) {
                tc = temp0[ty][tx];
                tn = temp0[ty - 1][tx];
                ts = temp0[ty + 1][tx];
                tw = temp0[ty][tx - 1];
                te = temp0[ty][tx + 1];

                temp1[ty][tx] = compute_point(yidx, xidx, row, col,
                                              tc, tn, ts, tw, te,
                                              power_local[ty][tx],
                                              Cap_1, Rx_1, Ry_1, Rz_1);
            } else {
                tc = temp1[ty][tx];
                tn = temp1[ty - 1][tx];
                ts = temp1[ty + 1][tx];
                tw = temp1[ty][tx - 1];
                te = temp1[ty][tx + 1];

                temp0[ty][tx] = compute_point(yidx, xidx, row, col,
                                              tc, tn, ts, tw, te,
                                              power_local[ty][tx],
                                              Cap_1, Rx_1, Ry_1, Rz_1);
            }
        }

        barrier(CLK_LOCAL_MEM_FENCE);
        buf = 1 - buf;
    }

    if (valid &&
        tx >= borderCols && tx < BLOCK_SIZE - borderCols &&
        ty >= borderRows && ty < BLOCK_SIZE - borderRows) {
        const int index = yidx * col + xidx;
        temp_dst[index] = (buf == 0) ? temp0[ty][tx] : temp1[ty][tx];
    }
}
